function openAboutDeep(parentKey, childKey){
  const pack=aboutModuleContent[currentLocale]||aboutModuleContent.en;
  const d=parentKey==="company-profile"?pack.profile:parentKey==="history"?pack.history:parentKey==="culture"?pack.culture:parentKey==="honors"?pack.honors:pack.responsibility;
  let title="", lead="", items=[];
  const idx=Number(childKey.split("-").pop())||0;
  if(childKey.startsWith("positioning-")){ [title,lead]=d.positioning[idx]; items=[d.positioningLead, ...(d.strengths||[]).slice(0,3).map(x=>x[0])]; }
  else if(childKey.startsWith("market-")){ const x=d.markets[idx]; title=x[0]; lead=x[1]; items=x[2]; }
  else if(childKey.startsWith("strength-")){ [title,lead]=d.strengths[idx]; items=[currentLocale.startsWith("zh")?"客户需求分析":"Customer requirement analysis",currentLocale.startsWith("zh")?"运输方案设计":"Transport solution design",currentLocale.startsWith("zh")?"全程操作协调":"End-to-end coordination",currentLocale.startsWith("zh")?"异常处理与反馈":"Exception handling and updates"]; }
  else if(childKey.startsWith("history-")){ const x=d.items[idx]; title=x[1]; lead=x[2]; items=[x[0],currentLocale.startsWith("zh")?"事件背景与阶段成果":"Background and milestone results",currentLocale.startsWith("zh")?"对业务网络的战略意义":"Strategic value to the business network",currentLocale.startsWith("zh")?"对客户服务能力的提升":"Customer-service capability improvement"]; }
  else if(childKey.startsWith("culture-value-")){ [title,lead]=d.values[idx]; items=[currentLocale.startsWith("zh")?"经营原则":"Operating principle",currentLocale.startsWith("zh")?"内部管理实践":"Internal management practice",currentLocale.startsWith("zh")?"客户服务应用":"Customer-service application",currentLocale.startsWith("zh")?"长期合作标准":"Long-term partnership standard"]; }
  else if(childKey.startsWith("profile-value-")){ title=d.values[idx]; lead=currentLocale.startsWith("zh")?`“${title}”是 NJOS GROUP 企业文化与日常运营的重要原则。`:`${title} is a core principle of NJOS GROUP culture and daily operations.`; items=[currentLocale.startsWith("zh")?"透明沟通":"Transparent communication",currentLocale.startsWith("zh")?"标准化执行":"Standardized execution",currentLocale.startsWith("zh")?"客户责任":"Customer commitment",currentLocale.startsWith("zh")?"持续改进":"Continuous improvement"]; }
  else if(childKey.startsWith("partner-")){ const x=d.partners[idx]; title=x[0]; lead=x[1]; items=[currentLocale.startsWith("zh")?"合作背景":"Cooperation background",currentLocale.startsWith("zh")?"航线与网络价值":"Route and network value",currentLocale.startsWith("zh")?"客户服务支持":"Customer-service support",currentLocale.startsWith("zh")?"长期合作方向":"Long-term cooperation direction"]; }
  else { const x=d.cards[idx]; title=x[0]; lead=x[1]; items=[currentLocale.startsWith("zh")?"责任目标":"Responsibility objective",currentLocale.startsWith("zh")?"执行措施":"Implementation measures",currentLocale.startsWith("zh")?"运营管理":"Operational management",currentLocale.startsWith("zh")?"持续改进":"Continuous improvement"]; }

  document.getElementById("nestedView").classList.remove("is-active");
  document.getElementById("deepView").classList.add("is-active");
  document.getElementById("deepBackLabel").textContent=currentLocale.startsWith("zh")?"返回上一级":"Back to module";
  document.getElementById("deepBreadcrumb").textContent=`NJOS GROUP / ${title}`;
  document.getElementById("deepMount").innerHTML=`
    <section class="deep-hero"><p class="eyebrow">NJOS GROUP · ${currentLocale.startsWith("zh")?"详细内容":"DETAIL"}</p><h1>${escapeHtml(title)}</h1><p>${escapeHtml(lead)}</p></section>
    <section class="deep-stats"><article class="deep-stat"><strong>01</strong><span>${currentLocale.startsWith("zh")?"内容概述":"Overview"}</span></article><article class="deep-stat"><strong>02</strong><span>${currentLocale.startsWith("zh")?"执行方式":"Execution"}</span></article><article class="deep-stat"><strong>03</strong><span>${currentLocale.startsWith("zh")?"持续提升":"Improvement"}</span></article></section>
    <section class="deep-grid"><article class="deep-panel"><h2>${currentLocale.startsWith("zh")?"详细说明":"Detailed Overview"}</h2><div class="deep-quote">${escapeHtml(lead)}</div><h3>${currentLocale.startsWith("zh")?"重点内容":"Key Points"}</h3><ul class="deep-list">${items.map(i=>`<li>${escapeHtml(i)}</li>`).join("")}</ul></article><article class="deep-panel"><h2>${currentLocale.startsWith("zh")?"图片与视频":"Images & Video"}</h2><div class="about-media-placeholder" style="min-height:280px"><span>＋</span><strong>${escapeHtml(pack.common.placeholder)}</strong></div><p>${currentLocale.startsWith("zh")?"后期可在此处添加真实项目照片、港口画面、证书、合作资料或企业视频。":"Verified project images, port footage, certificates, partnership materials or corporate video can be added here later."}</p></article></section>`;
  window.scrollTo({top:0,behavior:"smooth"});
}

