function openDetail(key){
 currentDetail=key;
 const d=activePack().details[key]||["Details","Detailed content will be added here."];
 document.getElementById("dialogContent").innerHTML=`<p class="eyebrow">NJOS GROUP</p><h2>${escapeHtml(d[0])}</h2><p>${escapeHtml(d[1])}</p>`;
 if(!dialog.open)dialog.showModal();
}

const languageSelect=document.getElementById("languageSelect");
languageSelect.addEventListener("change",()=>applyLocale(languageSelect.value));
function applyLocale(code){
 currentLocale=localePacks[code]?code:fallbackLocale;
 const u=activePack().ui;
 document.documentElement.lang=currentLocale;
 document.querySelectorAll("[data-i18n]").forEach(el=>{const k=el.dataset.i18n;if(u[k])el.textContent=u[k];});
 languageSelect.value=currentLocale;
 if(currentView!=="home")showView(currentView,true);
 if(currentDetail)openDetail(currentDetail);
}
applyLocale("en");

let globeStarted=false;
async function initGlobe(){
  if(globeStarted)return;
  globeStarted=true;

  const canvas=document.getElementById("globeCanvas");
  const stage=document.getElementById("globeStage");

  let THREE;
  try{
    THREE=await import("https://cdn.jsdelivr.net/npm/three@0.164.1/build/three.module.js/+esm");
  }catch(error){
    console.error("3D engine could not be loaded:",error);
    stage.classList.add("globe-fallback");
    stage.insertAdjacentHTML("beforeend",
      '<div class="fallback-message"><strong>Interactive Earth</strong><span>Please keep the internet connection active or deploy the site to a web host.</span></div>');
    return;
  }

  const scene=new THREE.Scene();
  const camera=new THREE.PerspectiveCamera(38,1,.1,100);
  camera.position.set(0,0,7.15);

  const renderer=new THREE.WebGLRenderer({canvas,alpha:true,antialias:true,powerPreference:"high-performance"});
  renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
  renderer.outputColorSpace=THREE.SRGBColorSpace;
  renderer.toneMapping=THREE.ACESFilmicToneMapping;
  renderer.toneMappingExposure=1.12;

  const root=new THREE.Group();
  root.rotation.x=-0.07;
  root.rotation.y=-0.38;
  scene.add(root);

  const textureLoader=new THREE.TextureLoader();
  const loadTexture=(url)=>new Promise((resolve,reject)=>textureLoader.load(url,resolve,undefined,reject));

  let earthMap,cloudMap;
  try{
    [earthMap,cloudMap]=await Promise.all([
      loadTexture("./assets/earth_atmos_2048.jpg"),
      loadTexture("./assets/earth_clouds_1024.png")
    ]);
    earthMap.colorSpace=THREE.SRGBColorSpace;
    cloudMap.colorSpace=THREE.SRGBColorSpace;
    earthMap.anisotropy=renderer.capabilities.getMaxAnisotropy();
  }catch(error){
    console.warn("Earth textures could not be loaded.",error);
  }

  const earthRadius=2.34;
  const earthMaterial=new THREE.MeshPhongMaterial({
    color:0xffffff,
    map:earthMap || null,
    shininess:24,
    specular:new THREE.Color(0x5e86a8),
    emissive:new THREE.Color(0x02070b),
    emissiveIntensity:.42
  });

  const earth=new THREE.Mesh(
    new THREE.SphereGeometry(earthRadius,128,128),
    earthMaterial
  );
  root.add(earth);

  // Gold night-side city glow: a second transparent shell creates a premium
  // black-gold appearance while preserving recognizable continents.
  const nightMaterial=new THREE.ShaderMaterial({
    transparent:true,
    blending:THREE.AdditiveBlending,
    depthWrite:false,
    uniforms:{
      time:{value:0},
      sunDirection:{value:new THREE.Vector3(-1.6,.8,2.2).normalize()}
    },
    vertexShader:`
      varying vec3 vNormalW;
      varying vec3 vPosW;
      void main(){
        vec4 worldPos=modelMatrix*vec4(position,1.0);
        vPosW=worldPos.xyz;
        vNormalW=normalize(mat3(modelMatrix)*normal);
        gl_Position=projectionMatrix*viewMatrix*worldPos;
      }
    `,
    fragmentShader:`
      varying vec3 vNormalW;
      varying vec3 vPosW;
      uniform float time;
      uniform vec3 sunDirection;
      float hash(vec3 p){
        p=fract(p*.1031);
        p+=dot(p,p.yzx+33.33);
        return fract((p.x+p.y)*p.z);
      }
      void main(){
        float daylight=max(dot(normalize(vNormalW),sunDirection),0.0);
        float night=pow(1.0-daylight,2.2);
        float latitude=abs(normalize(vPosW).y);
        float cityBand=smoothstep(.92,.15,latitude);
        float n=hash(floor(normalize(vPosW)*185.0));
        float cities=smoothstep(.93,.995,n)*cityBand*night;
        float pulse=.72+.28*sin(time*2.0+n*10.0);
        vec3 gold=vec3(1.0,.57,.12);
        gl_FragColor=vec4(gold,cities*pulse*.85);
      }
    `
  });
  const nightShell=new THREE.Mesh(new THREE.SphereGeometry(earthRadius*1.002,128,128),nightMaterial);
  root.add(nightShell);

  const clouds=new THREE.Mesh(
    new THREE.SphereGeometry(earthRadius*1.012,128,128),
    new THREE.MeshPhongMaterial({
      map:cloudMap || null,
      alphaMap:cloudMap || null,
      transparent:true,
      opacity:.34,
      depthWrite:false,
      blending:THREE.NormalBlending,
      color:0xffffff
    })
  );
  root.add(clouds);

  // Atmosphere rim.
  const atmosphere=new THREE.Mesh(
    new THREE.SphereGeometry(earthRadius*1.075,96,96),
    new THREE.ShaderMaterial({
      transparent:true,
      side:THREE.BackSide,
      blending:THREE.AdditiveBlending,
      depthWrite:false,
      vertexShader:`
        varying vec3 vNormal;
        void main(){
          vNormal=normalize(normalMatrix*normal);
          gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0);
        }
      `,
      fragmentShader:`
        varying vec3 vNormal;
        void main(){
          float rim=pow(0.68-dot(vNormal,vec3(0.0,0.0,1.0)),2.25);
          vec3 c=mix(vec3(.05,.22,.42),vec3(1.0,.55,.10),.22);
          gl_FragColor=vec4(c,rim*.72);
        }
      `
    })
  );
  root.add(atmosphere);

  // Star field with depth.
  const starGeometry=new THREE.BufferGeometry();
  const starPositions=[];
  const starColors=[];
  for(let i=0;i<2600;i++){
    const r=18+Math.random()*24;
    const theta=Math.random()*Math.PI*2;
    const phi=Math.acos(2*Math.random()-1);
    starPositions.push(
      r*Math.sin(phi)*Math.cos(theta),
      r*Math.cos(phi),
      r*Math.sin(phi)*Math.sin(theta)
    );
    const warm=Math.random()>.82;
    starColors.push(warm?1:.58,warm?.72:.72,warm?.33:1);
  }
  starGeometry.setAttribute("position",new THREE.Float32BufferAttribute(starPositions,3));
  starGeometry.setAttribute("color",new THREE.Float32BufferAttribute(starColors,3));
  const stars=new THREE.Points(starGeometry,new THREE.PointsMaterial({
    size:.035,
    transparent:true,
    opacity:.72,
    vertexColors:true,
    depthWrite:false
  }));
  scene.add(stars);

  scene.add(new THREE.HemisphereLight(0xaacfff,0x080604,1.25));
  const sunlight=new THREE.DirectionalLight(0xdceeff,3.4);
  sunlight.position.set(-3.2,2.2,5.2);
  scene.add(sunlight);
  const goldLight=new THREE.PointLight(0xffa929,22,18,2);
  goldLight.position.set(3.5,-1.5,4.5);
  scene.add(goldLight);

  const toVec=(lat,lon,r=earthRadius*1.018)=>{
    const phi=(90-lat)*Math.PI/180;
    const theta=(lon+180)*Math.PI/180;
    return new THREE.Vector3(
      -r*Math.sin(phi)*Math.cos(theta),
      r*Math.cos(phi),
      r*Math.sin(phi)*Math.sin(theta)
    );
  };

  const routes=new THREE.Group();
  root.add(routes);
  const newark=toVec(40.7357,-74.1724);

  const destinations=[
    {name:"Shanghai",lat:31.2304,lon:121.4737},
    {name:"Singapore",lat:1.3521,lon:103.8198},
    {name:"Tokyo",lat:35.6762,lon:139.6503},
    {name:"Busan",lat:35.1796,lon:129.0756},
    {name:"Dubai",lat:25.2048,lon:55.2708},
    {name:"Rotterdam",lat:51.9244,lon:4.4777},
    {name:"Hamburg",lat:53.5511,lon:9.9937},
    {name:"Los Angeles",lat:34.0522,lon:-118.2437},
    {name:"Santos",lat:-23.9608,lon:-46.3336}
  ];

  const routeParticles=[];
  destinations.forEach((destination,index)=>{
    const end=toVec(destination.lat,destination.lon);
    const distance=newark.distanceTo(end);
    const height=earthRadius+.65+distance*.18;
    const mid=newark.clone().add(end).multiplyScalar(.5).normalize().multiplyScalar(height);
    const curve=new THREE.QuadraticBezierCurve3(newark,mid,end);

    const tube=new THREE.Mesh(
      new THREE.TubeGeometry(curve,110,.0105,7,false),
      new THREE.MeshBasicMaterial({
        color:index%3===0?0xffd471:0xe8a42e,
        transparent:true,
        opacity:.72,
        blending:THREE.AdditiveBlending,
        depthWrite:false
      })
    );
    routes.add(tube);

    const endpoint=new THREE.Mesh(
      new THREE.SphereGeometry(.045,18,18),
      new THREE.MeshBasicMaterial({color:0xffd36c})
    );
    endpoint.position.copy(end);
    routes.add(endpoint);

    const glow=new THREE.Mesh(
      new THREE.SphereGeometry(.085,18,18),
      new THREE.MeshBasicMaterial({
        color:0xffa72e,
        transparent:true,
        opacity:.18,
        blending:THREE.AdditiveBlending,
        depthWrite:false
      })
    );
    glow.position.copy(end);
    routes.add(glow);

    for(let n=0;n<2;n++){
      const particle=new THREE.Mesh(
        new THREE.SphereGeometry(n===0?.028:.018,12,12),
        new THREE.MeshBasicMaterial({
          color:n===0?0xffffff:0xffba3b,
          transparent:true,
          opacity:.96,
          blending:THREE.AdditiveBlending,
          depthWrite:false
        })
      );
      particle.userData={
        curve,
        offset:(index/destinations.length+n*.37)%1,
        speed:.055+index*.002+n*.013
      };
      routes.add(particle);
      routeParticles.push(particle);
    }
  });

  const newarkCore=new THREE.Mesh(
    new THREE.SphereGeometry(.085,24,24),
    new THREE.MeshBasicMaterial({color:0xffffff})
  );
  newarkCore.position.copy(newark);
  root.add(newarkCore);

  const newarkGlow=new THREE.Mesh(
    new THREE.SphereGeometry(.19,24,24),
    new THREE.MeshBasicMaterial({
      color:0xffa520,
      transparent:true,
      opacity:.22,
      blending:THREE.AdditiveBlending,
      depthWrite:false
    })
  );
  newarkGlow.position.copy(newark);
  root.add(newarkGlow);

  let pointerX=0,pointerY=0;
  let dragging=false,lastX=0,lastY=0;
  let targetZoom=7.15;

  stage.addEventListener("pointermove",(event)=>{
    const rect=stage.getBoundingClientRect();
    pointerX=((event.clientX-rect.left)/rect.width-.5)*2;
    pointerY=((event.clientY-rect.top)/rect.height-.5)*2;
    if(dragging){
      root.rotation.y+=(event.clientX-lastX)*.006;
      root.rotation.x+=(event.clientY-lastY)*.004;
      lastX=event.clientX;
      lastY=event.clientY;
    }
  });
  stage.addEventListener("pointerdown",(event)=>{
    dragging=true;
    lastX=event.clientX;
    lastY=event.clientY;
    stage.setPointerCapture(event.pointerId);
  });
  stage.addEventListener("pointerup",(event)=>{
    dragging=false;
    stage.releasePointerCapture(event.pointerId);
  });
  stage.addEventListener("pointercancel",()=>dragging=false);
  stage.addEventListener("pointerleave",()=>{if(!dragging){pointerX=0;pointerY=0;}});
  stage.addEventListener("wheel",(event)=>{
    event.preventDefault();
    targetZoom=Math.max(5.2,Math.min(9.2,targetZoom+event.deltaY*.0032));
  },{passive:false});

  function resize(){
    const width=stage.clientWidth;
    const height=stage.clientHeight;
    renderer.setSize(width,height,false);
    camera.aspect=width/height;
    camera.updateProjectionMatrix();
  }
  window.addEventListener("resize",resize);
  resize();

  const clock=new THREE.Clock();
  function animate(){
    const elapsed=clock.getElapsedTime();
    if(!dragging) root.rotation.y+=.00125;
    clouds.rotation.y+=.00034;
    nightMaterial.uniforms.time.value=elapsed;
    camera.position.z+=(targetZoom-camera.position.z)*.06;

    // Bare-eye parallax: camera, globe and star field move at different depths.
    camera.position.x+=(pointerX*.22-camera.position.x)*.035;
    camera.position.y+=(-pointerY*.14-camera.position.y)*.035;
    root.position.x+=(pointerX*.12-root.position.x)*.035;
    root.position.y+=(-pointerY*.08-root.position.y)*.035;
    stars.rotation.y=-pointerX*.018;
    stars.rotation.x=pointerY*.012;

    routeParticles.forEach((particle)=>{
      const progress=(elapsed*particle.userData.speed+particle.userData.offset)%1;
      particle.position.copy(particle.userData.curve.getPoint(progress));
      const pulse=.72+.28*Math.sin(elapsed*8+progress*20);
      particle.scale.setScalar(pulse);
    });

    const beacon=1+.42*Math.sin(elapsed*3.3);
    newarkGlow.scale.setScalar(beacon);
    newarkGlow.material.opacity=.14+.13*(.5+.5*Math.sin(elapsed*3.3));

    renderer.render(scene,camera);
    requestAnimationFrame(animate);
  }
  animate();
}
